// =============================================================
// 🚨 ZACHYTÁVÁNÍ JS CHYB — pošle na backend pro diagnostiku
// =============================================================
(function setupErrorCapture() {
  let lastReportTs = 0;
  function reportError(payload) {
    const now = Date.now();
    if (now - lastReportTs < 1000) return;
    lastReportTs = now;
    try {
      fetch('../api/admin_klient_chyby.php', {
        method: 'POST',
        credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          app: 'admin',
          ...payload,
          url: location.href,
          user_info: (state?.admin?.jmeno || 'admin') + ' (' + (state?.admin?.role || '?') + ')',
        }),
      }).catch(() => {});
    } catch (e) {}
  }
  window.addEventListener('error', (e) => {
    reportError({
      msg: e.message || 'Unknown error',
      source: e.filename || '',
      line: e.lineno || 0,
      col: e.colno || 0,
      stack: e.error?.stack || '',
    });
  });
  window.addEventListener('unhandledrejection', (e) => {
    reportError({
      msg: '[Promise] ' + (e.reason?.message || String(e.reason)),
      stack: e.reason?.stack || '',
    });
  });
})();

// =============================================================
// HELPERS
// =============================================================
function esc(s) { return String(s ?? '').replace(/[&<>"']/g, (c) => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'})[c]); }

// =============================================================
// 🍞 TOAST NOTIFICATIONS — pro UX (nahradí alert())
// =============================================================
(function() {
  let host = null;
  function ensureHost() {
    if (!host) {
      host = document.createElement('div');
      host.className = 'toast-host';
      document.body.appendChild(host);
    }
    return host;
  }
  function toast(opts) {
    if (typeof opts === 'string') opts = { msg: opts };
    const { msg, title, type = 'info', duration = 4000 } = opts;
    const host = ensureHost();
    const icons = { success: '✓', error: '⚠', warn: '⚠', info: 'ⓘ' };
    const el = document.createElement('div');
    el.className = `toast toast-${type}`;
    el.style.setProperty('--toast-duration', duration + 'ms');
    el.innerHTML = `
      <div class="toast-icon">${icons[type] || icons.info}</div>
      <div class="toast-body">
        ${title ? `<div class="toast-title">${esc(title)}</div>` : ''}
        <div class="toast-msg">${esc(msg || '')}</div>
      </div>
      <button class="toast-close" aria-label="Zavřít">✕</button>
    `;
    const dismiss = () => {
      el.classList.add('is-closing');
      el.classList.remove('show');
      setTimeout(() => el.remove(), 250);
    };
    el.onclick = (e) => { if (e.target.closest('.toast-close') || e.target === el) dismiss(); };
    host.appendChild(el);
    requestAnimationFrame(() => el.classList.add('show'));
    if (duration > 0) setTimeout(dismiss, duration);
    return { dismiss };
  }
  window.toast = toast;
  window.toastSuccess = (msg, title) => toast({ msg, title, type: 'success' });
  window.toastError   = (msg, title) => toast({ msg, title, type: 'error', duration: 6000 });
  window.toastWarn    = (msg, title) => toast({ msg, title, type: 'warn',  duration: 5000 });
  window.toastInfo    = (msg, title) => toast({ msg, title, type: 'info' });
})();

// =============================================================
// ✏️ INLINE EDITING — generic helper
// =============================================================
// Použití v HTML:
//   <span class="inline-edit" data-inline-table="vyrobky" data-inline-id="123" data-inline-field="cena_bez_dph" data-inline-type="number">${fmt(v.cena_bez_dph)}</span>
// Click → input. Enter/Blur → save. Esc → cancel.
// Backend volá: PUT /api/admin_inline_edit.php { table, id, field, value }
(function() {
  document.addEventListener('click', async (e) => {
    const el = e.target.closest('.inline-edit:not(.is-editing)');
    if (!el) return;
    e.stopPropagation();

    const table = el.dataset.inlineTable;
    const id    = el.dataset.inlineId;
    const field = el.dataset.inlineField;
    const type  = el.dataset.inlineType || 'text';
    if (!table || !id || !field) return;

    const origHtml = el.innerHTML;
    const rawValue = el.dataset.inlineValue ?? el.textContent.trim();
    el.classList.add('is-editing');
    el.innerHTML = `<input type="${type === 'number' ? 'number' : 'text'}" ${type === 'number' ? 'step="0.01" min="0"' : ''} value="${esc(rawValue.replace(/[^\d.,\-]/g, '').replace(',', '.'))}">`;
    const input = el.querySelector('input');
    input.focus();
    input.select();

    let saved = false;
    const cancel = () => { if (saved) return; el.classList.remove('is-editing'); el.innerHTML = origHtml; };
    const save = async () => {
      if (saved) return;
      saved = true;
      const newVal = input.value;
      el.innerHTML = `${origHtml}<span class="inline-edit-spinner">⏳</span>`;
      try {
        await api('admin_inline_edit.php', {
          method: 'POST',
          body: JSON.stringify({ table, id: parseInt(id), field, value: newVal }),
        });
        // Refresh: callback nebo prostě reload tabulky
        el.classList.remove('is-editing');
        const display = type === 'number' ? fmt(parseFloat(newVal)) : esc(newVal);
        el.innerHTML = display;
        el.dataset.inlineValue = newVal;
        toastSuccess('Změna uložena');
      } catch (err) {
        el.classList.remove('is-editing');
        el.innerHTML = origHtml;
        toastError('Chyba: ' + err.message);
      }
    };
    input.onkeydown = (e) => {
      if (e.key === 'Enter') { e.preventDefault(); save(); }
      else if (e.key === 'Escape') { e.preventDefault(); cancel(); }
    };
    input.onblur = () => save();
  });
})();

// =============================================================
// 🖨️ PRINT QUEUE — collect docs → print all at once
// =============================================================
window.printQueue = (function() {
  const KEY = 'appek_print_queue';
  let items = [];
  try { items = JSON.parse(localStorage.getItem(KEY) || '[]'); } catch (e) { items = []; }

  function save() {
    try { localStorage.setItem(KEY, JSON.stringify(items)); } catch (e) {}
    renderFab();
  }

  function add(item) {
    // item = { type: 'faktura'|'dl'|'objednavka'|'cenovka', id: 123, label: 'FA-2026-0001' }
    if (items.find(x => x.type === item.type && x.id === item.id)) return false;
    items.push({ ...item, added_at: Date.now() });
    save();
    toastSuccess(`${item.label} přidán do tisku (${items.length})`);
    return true;
  }

  function remove(idx) { items.splice(idx, 1); save(); renderPanel(); }
  function clear()      { items = []; save(); closePanel(); }
  function getAll()     { return items.slice(); }
  function count()      { return items.length; }

  function renderFab() {
    let fab = document.getElementById('print-queue-fab');
    // 🆕 v2.9.106 — „Tisknout vše" vypínatelné v Nastavení → skryj plovoucí tlačítko
    if (typeof getPrintAllEnabled === 'function' && !getPrintAllEnabled()) {
      if (fab) fab.classList.remove('show');
      return;
    }
    if (items.length === 0) {
      if (fab) fab.classList.remove('show');
      return;
    }
    if (!fab) {
      fab = document.createElement('button');
      fab.id = 'print-queue-fab';
      fab.className = 'print-queue-fab';
      fab.onclick = togglePanel;
      document.body.appendChild(fab);
    }
    fab.innerHTML = `🖨️ <span>Tisknout vše</span> <span class="pq-badge">${items.length}</span>`;
    fab.classList.add('show');
  }

  let panel = null;
  function togglePanel() {
    if (panel && panel.classList.contains('show')) { closePanel(); return; }
    if (!panel) {
      panel = document.createElement('div');
      panel.className = 'print-queue-panel';
      document.body.appendChild(panel);
      document.addEventListener('click', (e) => {
        if (panel && !panel.contains(e.target) && !e.target.closest('#print-queue-fab')) closePanel();
      });
    }
    renderPanel();
    panel.classList.add('show');
  }

  function closePanel() { if (panel) panel.classList.remove('show'); }

  function renderPanel() {
    if (!panel) return;
    const icon = { faktura: '💰', dl: '📃', objednavka: '📋', cenovka: '🏷️', vyrobni_list: '🥖' };
    panel.innerHTML = `
      <div class="pq-head">
        <h3>🖨️ Fronta tisku (${items.length})</h3>
        <button class="pq-remove" onclick="closePqPanel()" title="Zavřít">×</button>
      </div>
      <div class="pq-list">
        ${items.map((it, i) => `
          <div class="pq-item">
            <span class="pq-icon">${icon[it.type] || '📄'}</span>
            <div class="pq-info">
              <div class="pq-title">${esc(it.label)}</div>
              <div class="pq-sub">${esc({faktura:'Faktura',dl:'Dodací list',objednavka:'Objednávka',cenovka:'Cenovka',vyrobni_list:'Výrobní list'}[it.type] || it.type)}</div>
            </div>
            <button class="pq-remove" onclick="printQueue.remove(${i})" title="Odebrat">×</button>
          </div>
        `).join('')}
      </div>
      <div class="pq-foot">
        <button class="btn-secondary" onclick="printQueue.clear()">🗑️ Vymazat</button>
        <button class="btn-primary btn-green" onclick="printQueue.printAll()">🖨️ Tisknout vše</button>
      </div>
    `;
  }

  async function printAll() {
    if (items.length === 0) return;
    closePanel();
    toastInfo(`Otevírám ${items.length} dokumentů…`);
    for (const it of items) {
      let url = null;
      if (it.type === 'faktura')     url = '../api/faktura.php?id=' + it.id;
      else if (it.type === 'dl')      url = '../api/dodaci_list.php?id=' + it.id;
      else if (it.type === 'vyrobni_list') url = '../api/vyrobni_list_print.php?id=' + it.id;
      if (url) {
        window.open(url, '_blank');
        // Stagger 250ms aby prohlížeč nezablokoval popup
        await new Promise(r => setTimeout(r, 250));
      }
    }
  }

  // Init FAB
  setTimeout(renderFab, 0);

  return { add, remove, clear, getAll, count, togglePanel, printAll, renderFab };
})();
window.closePqPanel = () => printQueue.togglePanel();

// 🆕 v2.9.106 — „Tisknout vše": zapínatelné/vypínatelné v Nastavení
window.getPrintAllEnabled = function() {
  try { return localStorage.getItem('appek_print_all_off') !== '1'; } catch (e) { return true; }
};
window.setPrintAllEnabled = function(on) {
  try { localStorage.setItem('appek_print_all_off', on ? '0' : '1'); } catch (e) {}
  try { printQueue.renderFab(); } catch (e) {}
  const st = document.getElementById('ns-print-all-status');
  if (st) {
    st.textContent = on ? '✓ Zapnuto' : '✕ Vypnuto';
    st.style.background = on ? 'var(--success-bg)' : '#FEE2E2';
    st.style.color = on ? 'var(--success-text)' : '#7F1D1D';
  }
};

