window._notifPanelEl = null;
window._notifPollTimer = null;

function fmtAgo(iso) {
  const d = new Date(iso.replace(' ', 'T'));
  const diff = Math.floor((Date.now() - d.getTime()) / 1000);
  if (diff < 60) return `${diff}s`;
  if (diff < 3600) return `${Math.floor(diff/60)} min`;
  if (diff < 86400) return `${Math.floor(diff/3600)} h`;
  return `${Math.floor(diff/86400)} d`;
}

window.refreshNotifBadge = async function(triggerFresh = false) {
  try {
    const r = await api('admin_notifications.php' + (triggerFresh ? '?fresh=1' : ''));
    const badge = document.getElementById('notif-badge');
    const btn = document.getElementById('btn-notifications');
    if (!btn) return;
    const n = r.unread_count || 0;
    // 🆕 v2.9.21 — Notifikace: JEN barva ikony (no count badge)
    if (badge) badge.style.display = 'none';   // count vždy skrytý
    if (n > 0) {
      btn.classList.add('has-unread');
    } else {
      btn.classList.remove('has-unread');
    }
    return r;
  } catch (e) { /* ignore */ }
};

window.toggleNotifPanel = async function() {
  if (window._notifPanelEl?.classList.contains('show')) {
    closeNotifPanel();
    return;
  }
  if (!window._notifPanelEl) {
    const el = document.createElement('div');
    el.className = 'notif-panel';
    document.body.appendChild(el);
    window._notifPanelEl = el;
    document.addEventListener('click', (e) => {
      if (!el.contains(e.target) && !e.target.closest('#btn-notifications')) closeNotifPanel();
    });
  }
  window._notifPanelEl.innerHTML = `
    <div class="notif-head">
      <h3>🔔 Notifikace</h3>
      <div class="notif-actions">
        <button onclick="markAllNotifRead()">✓ Vše přečteno</button>
      </div>
    </div>
    <div class="notif-list" id="notif-list">⏳</div>
    <div class="notif-foot">Auto-refresh každých 60s</div>
  `;
  window._notifPanelEl.classList.add('show');
  await loadNotifList(true);
};

function closeNotifPanel() {
  if (window._notifPanelEl) window._notifPanelEl.classList.remove('show');
}

async function loadNotifList(triggerFresh = false) {
  const host = document.getElementById('notif-list');
  if (!host) return;
  try {
    const r = await api('admin_notifications.php' + (triggerFresh ? '?fresh=1' : ''));
    const list = r.notifications || [];
    if (list.length === 0) {
      host.innerHTML = `<div class="notif-empty">🎉 Žádné nové notifikace</div>`;
      refreshNotifBadge();
      return;
    }

    // 🆕 v2.0.71 — SLUČOVÁNÍ stejných kind do jednoho řádku s počítadlem
    // (např. 5× "Nová objednávka #..." → "🛒 5 nových objednávek")
    const groups = {};
    for (const n of list) {
      const k = n.kind || 'other';
      if (!groups[k]) groups[k] = [];
      groups[k].push(n);
    }

    const kindLabels = {
      order_new:    { single: 'Nová objednávka',          plural: 'nových objednávek' },
      low_stock:    { single: 'Nízký sklad',              plural: 'surovin pod minimem' },
      sync_error:   { single: 'Sync chyba',               plural: 'sync chyb' },
      backup_stale: { single: 'Záloha DB',                plural: 'záloh DB pozadu' },
      app_update:   { single: 'Dostupný update',          plural: 'dostupných updatů' },
      license_expiring: { single: 'Licence expiruje',     plural: 'licencí expirují' },
      haccp_due:    { single: 'HACCP záznam',             plural: 'HACCP záznamů' },
      payment_due:  { single: 'Nezaplacená faktura',      plural: 'nezaplacených faktur' },
    };

    const html = [];
    for (const [kind, items] of Object.entries(groups)) {
      if (items.length === 1) {
        // Jediná notif — render normálně
        const n = items[0];
        html.push(`
          <div class="notif-item ${n.is_read == 0 ? 'is-unread' : ''} sev-${esc(n.severity)}" data-id="${n.id}" onclick="onNotifClick(${n.id}, '${esc(n.link || '')}')">
            <div class="notif-icon">${notifIcon(n.kind, n.severity)}</div>
            <div class="notif-body">
              <div class="notif-title">${esc(n.title)}</div>
              ${n.msg ? `<div class="notif-msg">${esc(n.msg)}</div>` : ''}
              <div class="notif-time">${fmtAgo(n.created_at)}</div>
            </div>
            <button class="notif-del" onclick="event.stopPropagation();deleteNotif(${n.id})" title="Smazat">×</button>
          </div>`);
      } else {
        // 2+ notif stejného kind — sloučit do jednoho řádku s počtem + expandable
        const first = items[0];
        const unreadCount = items.filter(x => x.is_read == 0).length;
        const isUnread = unreadCount > 0;
        const lbl = kindLabels[kind] || { single: 'Notifikace', plural: 'notifikací' };
        const summary = `${items.length} ${lbl.plural}`;
        const ids = items.map(x => x.id).join(',');
        const newestAt = items.map(x => x.created_at).sort().reverse()[0];

        html.push(`
          <div class="notif-item ${isUnread ? 'is-unread' : ''} sev-${esc(first.severity)} is-grouped" data-kind="${esc(kind)}" data-ids="${ids}" onclick="toggleNotifGroup('${esc(kind)}')" style="cursor:pointer">
            <div class="notif-icon">${notifIcon(kind, first.severity)}</div>
            <div class="notif-body">
              <div class="notif-title">
                ${esc(summary)}
                ${unreadCount > 0 ? `<span class="notif-count-badge">${unreadCount}</span>` : ''}
                <button class="notif-expand-btn" onclick="event.stopPropagation();toggleNotifGroup('${esc(kind)}')" title="Rozbalit">▾</button>
              </div>
              <div class="notif-msg">Klikni pro rozbalení (${items.length}× v skupině)</div>
              <div class="notif-time">Nejnovější: ${fmtAgo(newestAt)}</div>
            </div>
            <button class="notif-del" onclick="event.stopPropagation();deleteNotifGroup('${esc(kind)}', '${ids}')" title="Smazat všechny">×</button>
          </div>
          <div class="notif-group-children" id="notif-group-${esc(kind)}" style="display:none;padding-left:18px">
            ${items.map(n => `
              <div class="notif-item notif-child ${n.is_read == 0 ? 'is-unread' : ''} sev-${esc(n.severity)}" data-id="${n.id}" onclick="onNotifClick(${n.id}, '${esc(n.link || '')}')">
                <div class="notif-icon">·</div>
                <div class="notif-body">
                  <div class="notif-title">${esc(n.title)}</div>
                  ${n.msg ? `<div class="notif-msg">${esc(n.msg)}</div>` : ''}
                  <div class="notif-time">${fmtAgo(n.created_at)}</div>
                </div>
                <button class="notif-del" onclick="event.stopPropagation();deleteNotif(${n.id})" title="Smazat">×</button>
              </div>
            `).join('')}
          </div>`);
      }
    }
    host.innerHTML = html.join('');
    refreshNotifBadge();
  } catch (e) {
    host.innerHTML = `<div class="notif-empty">Chyba: ${esc(e.message)}</div>`;
  }
}

// 🆕 v2.0.71 — Expand/collapse group of same-kind notifications
window.toggleNotifGroup = function(kind) {
  const el = document.getElementById('notif-group-' + kind);
  if (!el) return;
  const isOpen = el.style.display === 'block';
  el.style.display = isOpen ? 'none' : 'block';
  // Update arrow indicator (find ▾/▴ button)
  const btn = document.querySelector(`.notif-item.is-grouped[data-kind="${kind}"] .notif-expand-btn`);
  if (btn) btn.textContent = isOpen ? '▾' : '▴';
};

// 🆕 v2.0.71 — Delete all notifications of a kind at once
window.deleteNotifGroup = async function(kind, idsCsv) {
  if (!confirm(`Smazat všechny notifikace typu "${kind}" (${idsCsv.split(',').length}×)?`)) return;
  const ids = idsCsv.split(',').filter(Boolean);
  try {
    await Promise.all(ids.map(id =>
      api('admin_notifications.php?action=delete', { method: 'POST', body: JSON.stringify({ id: parseInt(id, 10) }) })
    ));
    loadNotifList();
  } catch (e) { alert('Chyba: ' + e.message); }
};

function notifIcon(kind, severity) {
  const byKind = {
    order_new: '🛒', low_stock: '⚠️', sync_error: '☁️', backup_stale: '💾',
    license_expiring: '🔑', haccp_due: '📋', payment_due: '💰',
    app_update: '🆕',
  };
  return byKind[kind] || (severity === 'error' ? '❌' : severity === 'warn' ? '⚠️' : severity === 'success' ? '✓' : 'ⓘ');
}

window.onNotifClick = async function(id, link) {
  try {
    await api('admin_notifications.php?action=read', { method: 'POST', body: JSON.stringify({ id }) });
  } catch (e) { /* ignore */ }
  if (link && link.startsWith('#/')) {
    const parts = link.slice(2).split('/');
    closeNotifPanel();
    if (parts[0]) navigate(parts[0]);
  }
  refreshNotifBadge();
  loadNotifList();
};

window.markAllNotifRead = async function() {
  try {
    await api('admin_notifications.php?action=read', { method: 'POST', body: JSON.stringify({ all: true }) });
    toastSuccess('Vše označeno jako přečtené');
    loadNotifList();
  } catch (e) { alert('Chyba: ' + e.message); }
};

window.deleteNotif = async function(id) {
  try {
    await api('admin_notifications.php?action=delete', { method: 'POST', body: JSON.stringify({ id }) });
    loadNotifList();
  } catch (e) { /* ignore */ }
};

// =============================================================
// 📡 LICENSE HEARTBEAT — 1× denně pošli vendorovi technickou statistiku
// =============================================================
// Server-side endpoint: /api/license_heartbeat.php → POSTuje na vendor.appek.cz
// Customer admin spustí trigger jednou denně (localStorage chrání před spammen).
// Pokud vendor odpoví status:pirate → renderPirateNagBanner() ukáže warning.
async function triggerLicenseHeartbeatIfDue() {
  try {
    const HB_KEY = 'appek_heartbeat_last_date';
    const today = new Date().toISOString().slice(0, 10); // YYYY-MM-DD
    const lastDate = localStorage.getItem(HB_KEY);
    // Pokud už dnes proběhl, jen zkontroluj cached pirate flag (file → JS doesn't see; check via API)
    if (lastDate === today) {
      // Quick check: server-side flag — admin_pirate_status.php má cache i bez heartbeat trigger
      try {
        const r = await api('admin_pirate_status.php');
        if (r && r.pirate_flag) renderPirateNagBanner(r);
      } catch (e) { /* endpoint může chybět na starší instalaci — ignore */ }
      return;
    }
    // Spusť real heartbeat
    const r = await api('license_heartbeat.php', { method: 'POST', body: '{}' });
    localStorage.setItem(HB_KEY, today);
    if (r && r.status === 'pirate') {
      renderPirateNagBanner(r);
    } else {
      // Pokud existoval banner z předchozího pirate flagu a teď je clean → odstraň
      const ex = document.getElementById('appek-pirate-nag');
      if (ex) ex.remove();
    }
  } catch (e) {
    console.warn('[APPEK] heartbeat failed:', e.message || e);
  }
}

// 🆕 v2.6.1 — Anti-piracy HARD LOCK overlay
//    Pro vážné reasons (key_reuse, revoked, expired, unknown) zobrazí fullscreen blok.
//    Customer admin nemůže používat dokud nekontaktuje vendora.
function renderLicenseLockOverlay(payload) {
  if (document.getElementById('appek-license-lock')) return;
  const reasonLabels = {
    no_key:         'Chybí licenční klíč',
    invalid_format: 'Neplatný formát licenčního klíče',
    unknown_key:    'Licenční klíč není v naší databázi',
    key_reuse:      'Tento klíč je registrovaný pro jinou doménu',
    revoked_used:   'Tento klíč byl odvolán',
    expired_used:   'Vaše licence vypršela',
  };
  const reason = reasonLabels[payload.reason] || 'Problém s licencí';
  const overlay = document.createElement('div');
  overlay.id = 'appek-license-lock';
  overlay.style.cssText = `
    position: fixed; inset: 0; z-index: 999999;
    background: rgba(20, 0, 0, 0.85);
    backdrop-filter: blur(8px);
    -webkit-backdrop-filter: blur(8px);
    display: flex; align-items: center; justify-content: center;
    font-family: -apple-system, BlinkMacSystemFont, 'SF Pro Display', sans-serif;
  `;
  overlay.innerHTML = `
    <div style="background:#fff;max-width:520px;width:90%;border-radius:18px;padding:36px 30px;box-shadow:0 30px 80px rgba(0,0,0,0.5);text-align:center">
      <div style="font-size:60px;margin-bottom:14px">🔒</div>
      <h1 style="font-size:24px;font-weight:800;color:#991B1B;margin:0 0 8px">Licence zablokována</h1>
      <p style="font-size:15px;color:#1d1d1f;margin:0 0 4px;font-weight:600">${reason}</p>
      <p style="font-size:13px;color:#6e6e73;line-height:1.55;margin:14px 0 18px">
        ${payload.message ? payload.message.replace(/[<>]/g, '') : 'Tato instalace byla deaktivována. Pro obnovení kontaktujte dodavatele systému.'}
      </p>
      <div style="background:#FEE2E2;border:1px solid #FCA5A5;border-radius:10px;padding:12px 14px;margin-bottom:14px;text-align:left;font-size:12.5px;color:#7F1D1D;line-height:1.6">
        <strong>Možné důvody:</strong><br>
        • Klíč byl použit z více domén (anti-piracy)<br>
        • Klíč byl odvolán dodavatelem<br>
        • Licence vypršela bez obnovení
      </div>
      <a href="mailto:support@appek.cz?subject=Licence%20zablokována%20-%20${encodeURIComponent(location.hostname)}"
         style="display:inline-block;padding:12px 24px;background:linear-gradient(135deg,#BA7517,#854F0B);color:#fff;text-decoration:none;border-radius:10px;font-weight:700;font-size:14px;margin-bottom:8px">
        ✉️ Kontaktovat dodavatele
      </a>
      <!-- 🆕 v2.9.280 — podpora telefonem (jen pro kritické situace) -->
      <div style="font-size:12px;color:#7F1D1D;margin-top:6px">
        nebo telefon <a href="tel:+420733700808" style="color:#7F1D1D;font-weight:600;text-decoration:none">733 700 808</a>
      </div>
      <div style="font-size:11px;color:#86868b;margin-top:14px;font-family:monospace">
        Doména: ${location.hostname}<br>
        Reason: ${payload.reason || 'unknown'}
      </div>
    </div>
  `;
  document.body.appendChild(overlay);
  document.body.style.overflow = 'hidden';
}

function renderPirateNagBanner(payload) {
  // 🆕 v2.6.1 — Pro vážné reasons použij HARD LOCK overlay (ne banner)
  const hardLockReasons = ['key_reuse', 'revoked_used', 'expired_used', 'unknown_key'];
  if (hardLockReasons.includes(payload.reason)) {
    renderLicenseLockOverlay(payload);
    return;
  }
  if (document.getElementById('appek-pirate-nag')) return;
  const reasonLabels = {
    no_key:         { title: 'Chybí licenční klíč', cta: 'Kontaktovat dodavatele' },
    invalid_format: { title: 'Neplatný licenční klíč', cta: 'Zadat správný klíč' },
    unknown_key:    { title: 'Licenční klíč není v naší databázi', cta: 'Ověřit klíč u dodavatele' },
    key_reuse:      { title: 'Tento klíč je registrovaný pro jinou doménu', cta: 'Kontaktovat dodavatele' },
    revoked_used:   { title: 'Tento klíč byl odvolán',     cta: 'Obnovit licenci' },
    expired_used:   { title: 'Vaše licence vypršela',      cta: 'Obnovit licenci' },
  };
  const info = reasonLabels[payload.reason] || { title: 'Problém s licencí', cta: 'Více info' };
  const banner = document.createElement('div');
  banner.id = 'appek-pirate-nag';
  banner.style.cssText = `
    position: fixed; top: 0; left: 0; right: 0; z-index: 99999;
    background: linear-gradient(135deg, #DC2626, #991B1B);
    color: #fff; padding: 14px 22px; font-size: 14px; font-weight: 600;
    display: flex; align-items: center; gap: 14px; flex-wrap: wrap;
    box-shadow: 0 6px 20px rgba(220,38,38,0.4);
  `;
  banner.innerHTML = `
    <span style="font-size: 22px">🏴‍☠️</span>
    <div style="flex: 1; min-width: 240px">
      <div style="font-weight: 800; font-size: 15px">${info.title}</div>
      <div style="font-weight: 500; font-size: 12.5px; opacity: 0.95; margin-top: 2px">
        ${payload.message || 'Pro plnou funkčnost je třeba platná licence.'}
      </div>
    </div>
    <a href="mailto:support@appek.cz?subject=Licence%20-%20${encodeURIComponent(location.hostname)}"
       style="background: #fff; color: #DC2626; padding: 8px 16px; border-radius: 8px; text-decoration: none; font-weight: 700; font-size: 12.5px; white-space: nowrap">
      ✉️ ${info.cta}
    </a>
    <button onclick="document.getElementById('appek-pirate-nag').style.display='none'"
            style="background: rgba(255,255,255,0.18); border: none; color: #fff; padding: 6px 10px; border-radius: 6px; cursor: pointer; font-size: 11px">
      Skrýt
    </button>
  `;
  document.body.appendChild(banner);
  // Posuň body padding aby topbar nebyl překrytý
  document.body.style.paddingTop = (banner.offsetHeight) + 'px';
}

// Poll badge každých 60s, fresh generování jednou za 5 min
// 🆕 v2.0.71 — IMMEDIATE fresh při startu (aby update notif vyskočila hned po loginu)
window._lastFreshGen = 0;
function startNotifPolling() {
  if (window._notifPollTimer) return;
  // 🆕 v2.9.305 — pro POS-only roli skryj bell úplně (POS user nemůže reagovat na
  // notifikace typu "nová objednávka" → klick by ho stejně přesměroval na dashboard).
  const role = state.admin?.role || 'admin';
  if (role === 'pos') {
    const btn = document.getElementById('btn-notifications');
    if (btn) btn.style.display = 'none';
    return;
  }
  // První volání = ?fresh=1 → server detekuje update + emit notifikaci
  refreshNotifBadge(true);
  window._lastFreshGen = Date.now();
  // 🆕 Druhé volání za 3s — kontrola jestli mezitím přibyla update notif
  setTimeout(() => refreshNotifBadge(false), 3000);
  window._notifPollTimer = setInterval(() => {
    const triggerFresh = (Date.now() - window._lastFreshGen) > 5 * 60 * 1000;
    if (triggerFresh) window._lastFreshGen = Date.now();
    refreshNotifBadge(triggerFresh);
  }, 60 * 1000);
}

// =============================================================
// 📊 SVG SPARKLINE + BAR CHARTS (zero-dep)
// =============================================================
// 🆕 v2.9.248 — Sparkline upgrade: smooth bezier curve, glow, peak dot
window.sparklineSVG = function(data, opts = {}) {
  const {w = 280, h = 60, color = '#BA7517'} = opts;
  if (!data || data.length < 2) return '';  // tiše skryj (žádný šum)
  const min = Math.min(...data);
  const max = Math.max(...data);
  const range = max - min || 1;
  const stepX = w / (data.length - 1);
  const points = data.map((v, i) => [i * stepX, h - ((v - min) / range) * (h - 8) - 4]);

  // Smooth catmull-rom curve (vypadá hezky organicky, ne lomeno)
  let linePath = `M${points[0][0].toFixed(1)},${points[0][1].toFixed(1)}`;
  for (let i = 0; i < points.length - 1; i++) {
    const p0 = points[i - 1] || points[i];
    const p1 = points[i];
    const p2 = points[i + 1];
    const p3 = points[i + 2] || p2;
    const cp1x = p1[0] + (p2[0] - p0[0]) / 6;
    const cp1y = p1[1] + (p2[1] - p0[1]) / 6;
    const cp2x = p2[0] - (p3[0] - p1[0]) / 6;
    const cp2y = p2[1] - (p3[1] - p1[1]) / 6;
    linePath += ` C${cp1x.toFixed(1)},${cp1y.toFixed(1)} ${cp2x.toFixed(1)},${cp2y.toFixed(1)} ${p2[0].toFixed(1)},${p2[1].toFixed(1)}`;
  }
  const areaPath = linePath + ` L${w},${h} L0,${h} Z`;
  const last = points[points.length - 1];

  // Najdi peak (highest) — visually highlighted
  let peakIdx = 0;
  for (let i = 1; i < data.length; i++) if (data[i] > data[peakIdx]) peakIdx = i;
  const peak = points[peakIdx];

  // Unique gradient ID (multiple sparkliny na stránce)
  const gid = 'spk-' + Math.random().toString(36).slice(2, 8);

  return `
    <svg class="chart-svg" viewBox="0 0 ${w} ${h}" preserveAspectRatio="none" style="display:block;width:100%;height:${h}px;overflow:visible">
      <defs>
        <linearGradient id="${gid}" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stop-color="${color}" stop-opacity="0.35"/>
          <stop offset="100%" stop-color="${color}" stop-opacity="0"/>
        </linearGradient>
      </defs>
      <path d="${areaPath}" fill="url(#${gid})"/>
      <path d="${linePath}" fill="none" stroke="${color}" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" style="filter:drop-shadow(0 1px 2px ${color}33)"/>
      ${peakIdx !== data.length - 1 ? `<circle cx="${peak[0].toFixed(1)}" cy="${peak[1].toFixed(1)}" r="2" fill="${color}" opacity="0.5"/>` : ''}
      <circle cx="${last[0].toFixed(1)}" cy="${last[1].toFixed(1)}" r="3" fill="${color}" stroke="#fff" stroke-width="1.5"/>
    </svg>
  `;
};

window.barsSVG = function(data, opts = {}) {
  const {fmt: fmtFn = (v) => v} = opts;
  if (!data || data.length === 0) return '<div style="font-size:11px;color:#aaa;padding:14px">Žádná data</div>';
  const max = Math.max(...data.map(d => d.value));
  return `
    <div class="chart-bars" style="margin-bottom:24px">
      ${data.map(d => {
        const pct = max > 0 ? (d.value / max) * 100 : 0;
        return `
          <div class="chart-bar" style="height:${pct}%" title="${esc(d.label)}: ${fmtFn(d.value)}">
            <div class="chart-bar-value">${fmtFn(d.value)}</div>
            <div class="chart-bar-label">${esc((d.label || '').slice(0, 12))}</div>
          </div>
        `;
      }).join('')}
    </div>
  `;
};

