// =============================================================
// ⌘K COMMAND PALETTE — Linear/Notion-style universal search
// =============================================================
(function() {
  let overlay = null;
  let activeIdx = 0;
  let lastResults = [];

  // Statické navigation položky (vždy v paletě)
  function staticNav() {
    return [
      { kind: 'nav', id: 'dashboard',     icon: '📊', title: 'Přehled',          sub: 'Dashboard se statistikami', page: 'dashboard' },
      { kind: 'nav', id: 'objednavky',    icon: '📋', title: 'Objednávky',       sub: 'Seznam objednávek', page: 'objednavky' },
      { kind: 'nav', id: 'vyroba',        icon: '🥖', title: 'Výroba',           sub: 'Výrobní list, suroviny, sklad, HACCP', page: 'vyroba' },
      { kind: 'nav', id: 'dodaci_listy',  icon: '📃', title: 'Dodací listy',     sub: '', page: 'dodaci_listy' },
      { kind: 'nav', id: 'faktury',       icon: '💰', title: 'Faktury',          sub: '', page: 'faktury' },
      { kind: 'nav', id: 'vyrobky',       icon: '📦', title: 'Výrobky',          sub: 'Katalog výrobků', page: 'vyrobky' },
      { kind: 'nav', id: 'stitky',        icon: '🏷️', title: 'Štítky a cenovky', sub: '', page: 'stitky' },
      { kind: 'nav', id: 'haccp',         icon: '📋', title: 'HACCP',            sub: 'Bezpečnost potravin', page: 'haccp' },
      { kind: 'nav', id: 'odberatele',    icon: '👥', title: 'Odběratelé',       sub: '', page: 'odberatele' },
      { kind: 'nav', id: 'suroviny',      icon: '🌾', title: 'Suroviny',         sub: '', page: 'suroviny' },
      { kind: 'nav', id: 'sklad',         icon: '📦', title: 'Sklad',            sub: '', page: 'sklad' },
      { kind: 'nav', id: 'nastaveni',     icon: '⚙️', title: 'Nastavení',        sub: 'Firma, balíčky, údržba', page: 'nastaveni' },
    ];
  }

  function quickActions() {
    return [
      { kind: 'action', id: 'new_obj',     icon: '➕', title: 'Nová objednávka',  sub: 'Vytvořit novou objednávku', do: () => { closeCmdk(); navigate('objednavky'); setTimeout(() => window.otevritNovouObjednavku?.(), 200); } },
      { kind: 'action', id: 'pos_register',icon: '🧾', title: 'POS Kasa (nové okno)', sub: 'Standalone touch-grid POS pro restaurace', do: () => { closeCmdk(); window.openPOSWindow?.(); } },
      { kind: 'action', id: 'floorplan',   icon: '🗺️', title: 'Floor Plan Editor (nové okno)', sub: 'Drag&drop mapa stolů s šablonami', do: () => { closeCmdk(); window.open('floorplan.php','appek_fp','width='+screen.availWidth+',height='+screen.availHeight+',toolbar=no,menubar=no'); } },
      { kind: 'action', id: 'new_vyr',     icon: '➕', title: 'Nový výrobek',     sub: '',                          do: () => { closeCmdk(); navigate('vyrobky'); setTimeout(() => window.editVyrobek?.(), 200); } },
      { kind: 'action', id: 'new_odb',     icon: '➕', title: 'Nový odběratel',   sub: '',                          do: () => { closeCmdk(); navigate('odberatele'); setTimeout(() => window.editOdberatel?.(), 200); } },
      { kind: 'action', id: 'imp_cenik',   icon: '📊', title: 'Import ceníku (Excel/CSV)', sub: 'Hromadný import výrobků nebo surovin', do: () => { closeCmdk(); window.openImportCenik?.('vyrobky'); } },
      { kind: 'action', id: 'balicky',     icon: '🎁', title: 'Balíčky funkcí',  sub: 'Cukrárna, Lahůdky, Restaurace…', do: () => { closeCmdk(); navigate('nastaveni'); setTimeout(() => { state._nastaveniTab = 'balicky'; renderNastaveni(); }, 100); } },
      { kind: 'action', id: 'zalohy',      icon: '💾', title: 'Zálohy databáze', sub: '',                          do: () => { closeCmdk(); navigate('nastaveni'); setTimeout(() => { state._nastaveniTab = 'udrzba'; renderNastaveni(); }, 100); } },
    ];
  }

  async function searchDynamic(q) {
    if (!q || q.length < 2) return [];
    // Souběžně zkusíme vyrobky + odberatele (z cache pokud možno)
    const out = [];
    try {
      const v = await api('admin_vyrobky.php');
      (v.vyrobky || []).forEach(p => {
        if ((p.nazev || '').toLowerCase().includes(q) || (p.cislo || '').toLowerCase().includes(q)) {
          out.push({ kind: 'vyrobek', id: 'v' + p.id, icon: '📦', title: p.nazev, sub: `Výrobek · ${p.cislo || ''} · ${fmt(p.cena_bez_dph)}`, do: () => { closeCmdk(); navigate('vyrobky'); setTimeout(() => window.editVyrobek?.(p.id), 200); } });
        }
      });
    } catch (e) { /* ignore */ }
    try {
      const o = await api('admin_odberatele.php');
      (o.odberatele || []).forEach(c => {
        if ((c.nazev || '').toLowerCase().includes(q) || (c.cislo || '').toLowerCase().includes(q) || (c.ico || '').toLowerCase().includes(q)) {
          out.push({ kind: 'odberatel', id: 'o' + c.id, icon: '👥', title: c.nazev, sub: `Odběratel · ${c.cislo || ''} · ${c.ico || ''}`, do: () => { closeCmdk(); navigate('odberatele'); setTimeout(() => window.editOdberatel?.(c.id), 200); } });
        }
      });
    } catch (e) { /* ignore */ }
    return out.slice(0, 10);
  }

  function render(query) {
    if (!overlay) return;
    const q = (query || '').trim().toLowerCase();
    const nav = staticNav().filter(it => !q || it.title.toLowerCase().includes(q) || it.sub.toLowerCase().includes(q));
    const actions = quickActions().filter(it => !q || it.title.toLowerCase().includes(q));

    let html = '';
    if (actions.length) {
      html += `<div class="cmdk-section-title">⚡ Rychlé akce</div>`;
      html += actions.map((it, i) => itemHtml(it, i)).join('');
    }
    if (nav.length) {
      html += `<div class="cmdk-section-title">📁 Stránky</div>`;
      html += nav.map((it, i) => itemHtml(it, actions.length + i)).join('');
    }
    lastResults = [...actions, ...nav];

    const body = overlay.querySelector('.cmdk-results');
    if (lastResults.length === 0) {
      body.innerHTML = `<div class="cmdk-empty">🤷 Žádné výsledky pro „${esc(q)}"</div>`;
      // Zkus dynamický search výrobků/odběratelů
      if (q.length >= 2) {
        body.innerHTML = `<div class="cmdk-empty">⏳ Hledám výrobky a odběratele…</div>`;
        searchDynamic(q).then(dyn => {
          if (q !== (overlay.querySelector('.cmdk-input').value || '').trim().toLowerCase()) return;
          if (dyn.length === 0) {
            body.innerHTML = `<div class="cmdk-empty">🤷 Nic nenalezeno</div>`;
            return;
          }
          lastResults = dyn;
          activeIdx = 0;
          body.innerHTML = `<div class="cmdk-section-title">🔍 Hledání</div>` + dyn.map((it, i) => itemHtml(it, i)).join('');
          wireItems();
        });
      }
    } else {
      body.innerHTML = html;
      // Pokud uživatel hledá, i tak ukaž live výrobky/odběratele
      if (q.length >= 2) {
        searchDynamic(q).then(dyn => {
          if (q !== (overlay.querySelector('.cmdk-input').value || '').trim().toLowerCase()) return;
          if (dyn.length === 0) return;
          const dynHtml = `<div class="cmdk-section-title">🔍 Hledání</div>` + dyn.map((it, i) => itemHtml(it, lastResults.length + i)).join('');
          lastResults = [...lastResults, ...dyn];
          body.insertAdjacentHTML('beforeend', dynHtml);
          wireItems();
        });
      }
    }
    activeIdx = 0;
    wireItems();
  }

  function itemHtml(it, idx) {
    return `
      <div class="cmdk-item" data-idx="${idx}">
        <div class="cmdk-icon">${esc(it.icon || '·')}</div>
        <div class="cmdk-text">
          <div class="cmdk-title">${esc(it.title)}</div>
          ${it.sub ? `<div class="cmdk-sub">${esc(it.sub)}</div>` : ''}
        </div>
      </div>
    `;
  }

  function wireItems() {
    if (!overlay) return;
    overlay.querySelectorAll('.cmdk-item').forEach((el, idx) => {
      el.onclick = () => {
        const it = lastResults[parseInt(el.dataset.idx)];
        if (it) {
          if (it.do) it.do();
          else if (it.page) { closeCmdk(); navigate(it.page); }
        }
      };
      el.onmouseenter = () => setActive(parseInt(el.dataset.idx));
    });
    setActive(0);
  }

  function setActive(i) {
    activeIdx = Math.max(0, Math.min(lastResults.length - 1, i));
    if (!overlay) return;
    overlay.querySelectorAll('.cmdk-item').forEach(el => el.classList.remove('is-active'));
    const el = overlay.querySelector(`.cmdk-item[data-idx="${activeIdx}"]`);
    if (el) {
      el.classList.add('is-active');
      el.scrollIntoView({ block: 'nearest' });
    }
  }

  function openCmdk() {
    if (overlay) return;
    overlay = document.createElement('div');
    overlay.className = 'cmdk-overlay';
    // v2.9.24 — BULLETPROOF inline styly (immune to transform-parent bugy)
    overlay.style.cssText = [
      'position:fixed',
      'top:0','left:0','right:0','bottom:0',
      'width:100vw','height:100vh',
      'background:rgba(20,20,22,0.55)',
      '-webkit-backdrop-filter:blur(8px)',
      'backdrop-filter:blur(8px)',
      'z-index:99999',
      'display:flex',
      'align-items:flex-start',
      'justify-content:center',
      'padding-top:12vh',
      'padding-left:16px',
      'padding-right:16px',
      'opacity:0',
      'pointer-events:none',
      'transition:opacity 0.18s',
      'box-sizing:border-box',
      'margin:0'
    ].join(';');
    overlay.innerHTML = `
      <div class="cmdk" style="position:relative;width:min(640px,calc(100vw - 32px));max-width:100%;max-height:75vh;background:#fff;border-radius:16px;box-shadow:0 30px 80px rgba(0,0,0,0.45),0 4px 20px rgba(0,0,0,0.15);display:flex;flex-direction:column;overflow:hidden;z-index:100000">
        <div class="cmdk-search-row">
          <div class="cmdk-search-icon">🔍</div>
          <input class="cmdk-input" placeholder="Hledej cokoliv — výrobek, odběratele, akci…" autocomplete="off" autocorrect="off">
          <span class="cmdk-hint">ESC</span>
        </div>
        <div class="cmdk-results"></div>
        <div class="cmdk-footer">
          <span><kbd>↑↓</kbd> pohyb</span>
          <span><kbd>⏎</kbd> otevřít</span>
          <span style="flex:1"></span>
          <span><kbd>⌘</kbd> <kbd>K</kbd> přepnout</span>
        </div>
      </div>
    `;
    document.body.appendChild(overlay);
    // Force scroll lock — modal nesmí scrollovat pozadí
    document.body.style.overflow = 'hidden';
    requestAnimationFrame(() => {
      overlay.classList.add('show');
      overlay.style.opacity = '1';
      overlay.style.pointerEvents = 'auto';
    });

    const input = overlay.querySelector('.cmdk-input');
    input.focus();
    input.oninput = () => render(input.value);
    overlay.onclick = (e) => { if (e.target === overlay) closeCmdk(); };
    document.addEventListener('keydown', onKey);
    render('');
  }

  function closeCmdk() {
    if (!overlay) return;
    overlay.classList.remove('show');
    overlay.style.opacity = '0';
    overlay.style.pointerEvents = 'none';
    // Restore body scroll
    document.body.style.overflow = '';
    document.removeEventListener('keydown', onKey);
    setTimeout(() => { overlay?.remove(); overlay = null; }, 200);
  }

  function onKey(e) {
    if (!overlay) return;
    if (e.key === 'Escape')      { e.preventDefault(); closeCmdk(); }
    else if (e.key === 'ArrowDown') { e.preventDefault(); setActive(activeIdx + 1); }
    else if (e.key === 'ArrowUp')   { e.preventDefault(); setActive(activeIdx - 1); }
    else if (e.key === 'Enter') {
      e.preventDefault();
      const it = lastResults[activeIdx];
      if (it) {
        if (it.do) it.do();
        else if (it.page) { closeCmdk(); navigate(it.page); }
      }
    }
  }

  // Global shortcut ⌘K / Ctrl+K (mimo input/textarea pokud je text)
  document.addEventListener('keydown', (e) => {
    const isCmdK = (e.metaKey || e.ctrlKey) && (e.key === 'k' || e.key === 'K');
    if (isCmdK) {
      e.preventDefault();
      if (overlay) closeCmdk(); else openCmdk();
    }
  });

  window.openCmdk = openCmdk;
})();

// =============================================================
// 📊 TOP LOADING BAR — Linear/YouTube style
// =============================================================
(function() {
  let bar = null, count = 0, timer = null;
  function ensureBar() {
    if (!bar) {
      const wrap = document.createElement('div');
      wrap.className = 'top-progress';
      bar = document.createElement('div');
      bar.className = 'top-progress-bar';
      wrap.appendChild(bar);
      document.body.appendChild(wrap);
    }
    return bar;
  }
  function start() {
    const b = ensureBar();
    count++;
    b.style.opacity = '1';
    b.style.width = Math.min(85, parseFloat(b.style.width) || 0) + Math.random() * 15 + 10 + '%';
  }
  function done() {
    count = Math.max(0, count - 1);
    if (count > 0) return;
    const b = ensureBar();
    b.style.width = '100%';
    clearTimeout(timer);
    timer = setTimeout(() => {
      b.style.opacity = '0';
      setTimeout(() => { b.style.width = '0%'; }, 300);
    }, 200);
  }
  window.topProgressStart = start;
  window.topProgressDone  = done;
})();
function fmt(n) {
  // 🌍 T4 — locale-aware formátování měny. Default cs-CZ/CZK, ale respektuje getCurrentLocale().
  try {
    const cfg = (typeof window.getCurrentLocale === 'function') ? window.getCurrentLocale() : null;
    const locale   = (cfg && cfg.locale)   || 'cs-CZ';
    const currency = (cfg && cfg.currency) || 'CZK';
    return new Intl.NumberFormat(locale, { style: 'currency', currency, minimumFractionDigits: 2, maximumFractionDigits: 2 }).format(n || 0);
  } catch (e) {
    return new Intl.NumberFormat('cs-CZ', { style: 'currency', currency: 'CZK', minimumFractionDigits: 2, maximumFractionDigits: 2 }).format(n || 0);
  }
}

// URL na PDF dodacího listu — ruční DL (bez objednávky) jdou přes ?dl_id, ostatní přes ?id (objednávka)
function dlPdfUrl(d) {
  if (d.objednavka_id) return `../api/dodaci_list.php?id=${d.objednavka_id}`;
  return `../api/dodaci_list.php?dl_id=${d.id}`;
}

/**
 * Unifikovaný badge pro odkaz na DL / FA / OBJ.
 * type: 'dl' | 'fa' | 'obj'
 * url:  cíl odkazu (string) nebo null pokud nedostupné
 * label: text uvnitř (např. "📃 DL", "💰 FA", "🛒 OBJ")
 * Když url je null/empty, vrátí disabled (šedý) badge.
 * Když k dispozici, vrátí klikatelný odkaz s barvou podle typu (DL = amber, FA = zelená, OBJ = modrá).
 */
function docBadge(type, url, label, opts = {}) {
  const title = opts.title || '';
  if (url) {
    const onclick = opts.onclick ? `onclick="${opts.onclick};return false"` : '';
    const target  = opts.onclick ? '' : 'target="_blank"';
    return `<a href="${onclick ? '#' : url}" ${target} ${onclick} class="doc-badge ${type}" title="${esc(title)}">${label}</a>`;
  }
  // Nedostupné: ne-klikatelný šedý badge
  return `<span class="doc-badge ${type} unavailable" title="${esc(opts.disabledTitle || 'Není k dispozici')}">${label}</span>`;
}
function fmtDate(s) {
  if (!s) return '';
  const d = new Date(s);
  return d.toLocaleDateString('cs-CZ', { day: 'numeric', month: 'numeric', year: 'numeric' });
}
function fmtDateTime(s) {
  if (!s) return '';
  const d = new Date(s);
  return d.toLocaleDateString('cs-CZ', { day: 'numeric', month: 'numeric' }) + ' ' + d.toLocaleTimeString('cs-CZ', { hour: '2-digit', minute: '2-digit' });
}
function statusLabel(s) {
  const m = { nova: 'Nová', potvrzena: 'Potvrzená', ve_vyrobe: 'Ve výrobě', pripravena: 'Připravená', expedovana: 'Expedována', dorucena: 'Doručena', zrusena: 'Zrušena' };
  return m[s] || s;
}

// =============================================================
// 📡 API helper s krátkodobou GET cache (snižuje lag při přepínání stránek)
// =============================================================
const _apiCache = new Map();       // path → { data, expires }
const _apiCacheTTL = 4000;          // 4s — krátká doba, ať uživatel vidí čerstvá data po editaci
function _apiCacheKey(path) { return path; }
function apiCacheInvalidate(prefix = '') {
  if (!prefix) { _apiCache.clear(); return; }
  for (const k of _apiCache.keys()) if (k.startsWith(prefix)) _apiCache.delete(k);
}

// =============================================================
// 🗑️ DELETE CONFIRMATION — volitelně 2× potvrzení (proti omylem mazání)
// Uživatel si může v Nastavení vypnout druhý krok.
// =============================================================
// Persistence: localStorage klíč 'confirm_delete_2x' = '1' | '0' (default '1' = zapnuto)
window.getConfirmDelete2xEnabled = function() {
  try {
    const v = localStorage.getItem('confirm_delete_2x');
    return v === null ? true : v === '1';   // default ON
  } catch { return true; }
};
window.setConfirmDelete2xEnabled = function(on) {
  try { localStorage.setItem('confirm_delete_2x', on ? '1' : '0'); } catch {}
  // Aktualizuj vizuální status badge v Nastavení (pokud je viditelný)
  const badge = document.getElementById('ns-confirm-2x-status');
  if (badge) {
    badge.textContent = on ? '✓ Zapnuto' : '✕ Vypnuto';
    if (on) {
      badge.style.background = 'var(--success-bg)';
      badge.style.color = 'var(--success-text)';
    } else {
      badge.style.background = '#FEE2E2';
      badge.style.color = '#7F1D1D';
    }
  }
};

// Použití:
//   if (!await confirmDelete2x('výrobek "Bageta"')) return;
// nebo
//   if (!await confirmDelete2x({ co: 'fakturu č. 2026-001', detail: 'Faktura se nenávratně smaže.' })) return;
window.confirmDelete2x = async function(arg) {
  // Akceptuje string (jen název) i objekt { co, detail }
  const co = typeof arg === 'string' ? arg : (arg?.co || 'tuto položku');
  const detail = typeof arg === 'object' ? (arg?.detail || '') : '';

  // 1. krok — běžný prompt
  const krok1 = confirm(`Opravdu smazat ${co}?${detail ? '\n\n' + detail : ''}`);
  if (!krok1) return false;

  // 2. krok — definitivní potvrzení (nepřeskočitelné), JEN pokud je v nastavení zapnuté
  if (!getConfirmDelete2xEnabled()) return true;
  const krok2 = confirm(`⚠️ POSLEDNÍ POTVRZENÍ\n\nOpravdu nevratně smazat ${co}?\n\nKlikněte OK pouze pokud si jste 100% jistí. Tato akce nelze vrátit zpět.\n\n(Druhý krok můžete vypnout v Nastavení.)`);
  return krok2;
};

async function api(path, opts = {}) {
  const method = (opts.method || 'GET').toUpperCase();

  // Auto-stringify body pokud je objekt (ne FormData ani string)
  if (opts.body && typeof opts.body === 'object' && !(opts.body instanceof FormData)) {
    opts.body = JSON.stringify(opts.body);
  }

  // Cache jen pro GET requesty
  if (method === 'GET') {
    const key = _apiCacheKey(path);
    const cached = _apiCache.get(key);
    if (cached && cached.expires > Date.now()) {
      return cached.data;
    }
  }

  // 🔒 v2.6.0 SECURITY: pošli CSRF token v každém POST/PUT/DELETE
  const csrfToken = (typeof state !== 'undefined' && state && state.csrfToken) || localStorage.getItem('appek_csrf_token') || '';
  const baseHeaders = {};
  if (opts.body && !(opts.body instanceof FormData)) {
    baseHeaders['Content-Type'] = 'application/json';
  }
  if (csrfToken && method !== 'GET') {
    baseHeaders['X-CSRF-Token'] = csrfToken;
  }

  if (typeof topProgressStart === 'function') topProgressStart();
  let res, data;
  try {
    res = await fetch(`${API}/${path}`, {
      credentials: 'include',
      headers: { ...baseHeaders, ...(opts.headers || {}) },
      ...opts,
    });
    data = await res.json().catch(() => ({}));
    // 🔒 Uchyt CSRF token z přihlašovací odpovědi (admin_login.php)
    if (data && data.csrf_token) {
      try {
        if (typeof state !== 'undefined' && state) state.csrfToken = data.csrf_token;
        localStorage.setItem('appek_csrf_token', data.csrf_token);
      } catch (e) {}
    }
  } finally {
    if (typeof topProgressDone === 'function') topProgressDone();
  }
  // 🆕 v2.9.321 — Přilep request_id k error message, aby user mohl říct "rozbité, reqId=abc12345"
  // a admin to našel v Diagnostice → 🐛 Chyby aplikace přes search.
  if (!res.ok) {
    const err = new Error(data.error || 'Chyba serveru');
    if (data.request_id) {
      err.message += ' (reqId: ' + data.request_id + ')';
      err.requestId = data.request_id;
    }
    if (data.debug) err.debug = data.debug;
    throw err;
  }

  // Ulož do cache po úspěšném GET
  if (method === 'GET') {
    _apiCache.set(_apiCacheKey(path), { data, expires: Date.now() + _apiCacheTTL });
  }
  // Při POST/PUT/DELETE invaliduj odpovídající GET cache, aby se po editaci načetlo čerstvé
  if (method !== 'GET') {
    apiCacheInvalidate(path.split('?')[0]);
  }
  return data;
}

// =============================================================
// 🚀 DEBOUNCE — pro vyhledávací inputy (nehledat při každém znaku)
// =============================================================
window._debounceTimers = window._debounceTimers || {};
window.debounce = function(key, fn, delay = 250) {
  clearTimeout(window._debounceTimers[key]);
  window._debounceTimers[key] = setTimeout(fn, delay);
};

// =============================================================
// 🎨 THEME SYSTEM — výchozí / win98 / tmavý
// Aplikuje se přes html.theme-{id}. Pure CSS, žádné zásahy do funkčnosti.
// =============================================================
const APP_THEMES = ['default', 'win98', 'dark', 'apple'];
window.getAppTheme = function() {
  try {
    const t = localStorage.getItem('appTheme');
    return APP_THEMES.includes(t) ? t : 'default';
  } catch { return 'default'; }
};
window.setAppTheme = function(theme) {
  if (!APP_THEMES.includes(theme)) theme = 'default';
  try { localStorage.setItem('appTheme', theme); } catch {}
  applyAppTheme();
  // Re-render Nastavení (aktivní karta) — aby se updatly badge "Aktivní"
  if (state.current === 'nastaveni') renderNastaveni();
};
function applyAppTheme() {
  const t = getAppTheme();
  const html = document.documentElement;
  // Odstraň všechny theme-* třídy a 'dark' (legacy)
  APP_THEMES.forEach(x => html.classList.remove('theme-' + x));
  html.classList.remove('dark');
  // Aplikuj aktuální
  html.classList.add('theme-' + t);
  // Pro zpětnou kompatibilitu (existující html.dark CSS) přidej 'dark' i u darku
  if (t === 'dark') html.classList.add('dark');
}
// Aplikuj theme okamžitě při startu (před renderem)
applyAppTheme();

// =============================================================
// 📏 DENSITY (HUSTOTA UI) — kompaktní / pohodlné / prostorné
// CSS variabily nastavují multiplier pro padding/font/gap.
// Pro starší / slabozraké uživatele = pohodlnější UI.
// =============================================================
const APP_DENSITIES = ['compact', 'comfortable', 'spacious', 'extreme'];
window.getAppDensity = function() {
  try {
    const d = localStorage.getItem('appDensity');
    return APP_DENSITIES.includes(d) ? d : 'comfortable';
  } catch { return 'comfortable'; }
};
window.setAppDensity = function(density) {
  if (!APP_DENSITIES.includes(density)) density = 'comfortable';
  try { localStorage.setItem('appDensity', density); } catch {}
  applyAppDensity();
  if (state?.current === 'nastaveni') renderNastaveni();
};
function applyAppDensity() {
  const d = getAppDensity();
  const html = document.documentElement;
  APP_DENSITIES.forEach(x => html.classList.remove('density-' + x));
  html.classList.add('density-' + d);
}
applyAppDensity();

