              return `<label class="checkbox-row" style="background:white;padding:5px 10px;border-radius:6px;border:1px solid #D5E5F5">
                <input type="checkbox" data-stav-notif value="${s.k}" ${aktivni ? 'checked' : ''}>
                <span>${s.l}</span>
              </label>`;
