  cenovkaPocet: 1,
  vlozitEan: true,             // čárový kód EAN-13 na cenovce
  // Moje štítky (vlastní):
  mojeStitky: [],
  vybraneMoje: new Set(),
  mojeQ: '',
  // Šablony (z editoru) — když je vybraná, přebije výchozí layout cenovky
  sablonaId: null,
